  const handleFetchError = (err: unknown, endpoint: string): never => {
    if (err instanceof DOMException && err.name === 'TimeoutError')
      throw ToolError.timeout(`API request timed out: ${endpoint}`);
    if (err instanceof DOMException && err.name === 'AbortError') throw new ToolError('Request was aborted', 'aborted'); // NO CATEGORY
    throw new ToolError(`Network error: ...`, 'network_error', { category: 'internal', retryable: true });
  };

